(function() {
            let userInteracted = false;
            let blockedVideos = new WeakSet();

            const trackUserInteraction = function() {
                userInteracted = true;
            };

            document.addEventListener('click', trackUserInteraction);
            document.addEventListener('play', trackUserInteraction);

            document.addEventListener('scroll', () => {
                userInteracted = false;
            });

            // Override play() to block autoplay from programmatic triggers
            const originalPlay = HTMLMediaElement.prototype.play;
            HTMLMediaElement.prototype.play = function() {
                if (userInteracted || (event && event.isTrusted)) {
                    return originalPlay.call(this);
                }

                console.log('[Autoplay Blocker] Programmatic autoplay blocked.');
                blockedVideos.add(this);
                setTimeout(() => {
                    if (!this.paused && blockedVideos.has(this)) {
                        this.pause();
                    }
                }, 0);

                return Promise.reject(new DOMException('Autoplay blocked', 'NotAllowedError'));
            };

            // Force disable autoplay property
            const originalAutoplay = Object.getOwnPropertyDescriptor(HTMLMediaElement.prototype, 'autoplay');
            Object.defineProperty(HTMLMediaElement.prototype, 'autoplay', {
                get: function() {
                    return originalAutoplay.get.call(this);
                },
                set: function(value) {
                    return originalAutoplay.set.call(this, false);
                },
                configurable: true
            });

            function monitorPlayback(media) {
                if (media._autoplayHandled) return;

                media.removeAttribute('autoplay');
                media.autoplay = false;
                media.removeAttribute('muted');
                media.muted = false;

                media.addEventListener('play', function() {
                    if (!userInteracted && !blockedVideos.has(this)) {
                        console.log('[Autoplay Blocker] Unintended play blocked.');
                        this.pause();
                        blockedVideos.add(this);
                    }
                });

                media.addEventListener('loadstart', function() {
                    if (!userInteracted) {
                        this.autoplay = false;
                        this.muted = false;
                    }
                });

                media._autoplayHandled = true;
            }

            function processMediaElements(node) {
                if (!node) return;

                // Regular video/audio elements
                if (node.tagName === 'VIDEO' || node.tagName === 'AUDIO') {
                    monitorPlayback(node);
                }

                // Query inside shadow DOM (e.g., YouTube Shorts, TikTok)
                if (node.shadowRoot) {
                    try {
                        node.shadowRoot.querySelectorAll('video, audio').forEach(monitorPlayback);
                    } catch (e) {}
                }

                // Query child elements
                if (node.querySelectorAll) {
                    try {
                        node.querySelectorAll('video, audio').forEach(monitorPlayback);
                    } catch (e) {}
                }

                // Recurse deeply
                if (node.children) {
                    Array.from(node.children).forEach(processMediaElements);
                }
            }

            const observer = new MutationObserver(mutations => {
                mutations.forEach(mutation => {
                    mutation.addedNodes.forEach(node => {
                        if (node.nodeType === 1) {
                            processMediaElements(node);
                        }
                    });
                });
            });

            function initObserver() {
                if (document.body) {
                    observer.observe(document.body, { childList: true, subtree: true });
                } else {
                    setTimeout(initObserver, 50);
                }
            }

            // Initial scan
            function initialScan() {
                processMediaElements(document.body);
            }

            // Delayed fallback scans (for missed SPA loads)
            setInterval(() => {
                processMediaElements(document.body);
            }, 2000);

            initialScan();
            initObserver();

            if (document.readyState === 'loading') {
                document.addEventListener('DOMContentLoaded', initialScan);
            }
        })();